import valueobject.*;

public abstract class Event {
    private final EventId id;
    private final TitreEvenement titre;
    private final Proprietaire proprietaire;
    private final DateEvenement dateDebut;

    public Event(EventId id, TitreEvenement titre, Proprietaire proprietaire, DateEvenement dateDebut) {
        this.id = id;
        this.titre = titre;
        this.proprietaire = proprietaire;
        this.dateDebut = dateDebut;
    }

    public EventId id() { return id; }
    public TitreEvenement titre() { return titre; }
    public Proprietaire proprietaire() { return proprietaire; }
    public DateEvenement dateDebut() { return dateDebut; }

    public abstract String description();
    public abstract boolean estDansPeriode(valueobject.Periode periode);
    public abstract valueobject.Periode occupation();

    public boolean estEnConflitAvec(Event autre) {
        return this.occupation().chevauche(autre.occupation());
    }
}

package event;

import valueobject.*;

public final class RendezVousPersonnel extends Event {
    private final DureeEvenement duree;

    public RendezVousPersonnel(EventId id, TitreEvenement titre, Proprietaire proprietaire,
                                DateEvenement dateDebut, DureeEvenement duree) {
        super(id, titre, proprietaire, dateDebut);
        this.duree = duree;
    }

    public DureeEvenement duree() {
        return duree;
    }

    @Override
    public String description() {
        return "RDV : " + titre() + " à " + dateDebut();
    }

    @Override
    public boolean estDansPeriode(Periode periode) {
        return periode.contient(dateDebut());
    }

    @Override
    public Periode occupation() {
        return new Periode(dateDebut(), duree.ajouterA(dateDebut()));
    }
}

